// Update chNum from the actual chapter found
chNum = thisChapter.number;
const chLabel = isProl ? 'Prologue' : (isEpil ? 'Epilogue' : 'Chapter ' + chNum);

// Format book outline context
const charList = (bookOutline.characters || []).map(c =>
  '- ' + c.name + ' (' + c.role + '): ' + c.arc + (c.description ? ' — ' + c.description : '')
).join('\n');

// Only include surrounding chapters (±2) to keep prompt focused
const allChapters = bookOutline.chapters || [];
const nearbyChapters = allChapters.filter(ch => 
