    'Ch ' + ch.number + ' — ' + ch.title + ': ' + ch.brief + (ch.arc_notes ? ' [Book Arc Beat: ' + ch.arc_notes + ']' : '')
  ).join('\n');

// Find surrounding chapters for context
const prevCh = bookOutline.chapters.find(ch => ch.number === chNum - 1);
const nextCh = bookOutline.chapters.find(ch => ch.number === chNum + 1);

const instructions = trigger.instructions || '';

// Fill story arc placeholders with actual project data
const protagonist = (bookOutline.characters || []).find(c => c.role === 'Protagonist');
const protagonistDesc = protagonist ? protagonist.name + ' — ' + protagonist.arc : 'See characters in book outline';

function fillArcPlaceholders(arcText) {
  if (!arcText) return '';
  let filled = arcText;
  filled = filled.replace(/\[a full book[^\]]*\]/gi, 'a detailed chapter outline with sub-chapters');
  filled = filled.replace(/\[Book \/ Chapter[^\]]*\]/gi, 'Chapter outline');
  filled = filled.replace(/\[e\.g\., thriller[^\]]*\]/gi, genreData.genre_name || 'fiction');
  filled = filled.replace(/\[Describe briefly[^\]]*\]/gi, protagonistDesc);
  filled = filled.replace(/\[What is the core[^\]]*\]/gi, bookOutline.premise || 'See premise');
  filled = filled.replace(/\[Where and when[^\]]*\]/gi, thisChapter ? thisChapter.brief.substring(0, 100) : 'See chapter brief');
  filled = filled.replace(/\[What does the protagonist[^\]]*\]/gi, 'See book outline character arcs');
  filled = filled.replace(/\[e\.g\., 1,000 words[^\]]*\]/gi, '3-8 sub-chapter outlines of 5000 words each');
  filled = filled.replace(/\[Hero[^\]]*\]/gi, protagonistDesc);
  filled = filled.replace(/\[.*?Main character[^\]]*\]/gi, protagonistDesc);
  filled = filled.replace(/\[.*?Setting[^\]]*\]/gi, 'See chapter brief');
  filled = filled.replace(/\[.*?Length goal[^\]]*\]/gi, '3-8 sub-chapter outlines');
  filled = filled.replace(/\[.*?Genre[^\]]*\]/gi, genreData.genre_name || 'fiction');
  return filled;
}

const filledBookArc = fillArcPlaceholders(bookArcPrompt);
const filledChapterArc = fillArcPlaceholders(chapterArcPrompt);

const prompt = `You are a skilled story architect creating a detailed CHAPTER OUTLINE for ${chLabel} of "${bookOutline.title}", a ${genreData.genre_name || 'fiction'} novel.

## Your Task
Create a detailed chapter outline that breaks this chapter into SUB-CHAPTERS (mini-sections that together form the complete chapter). Each sub-chapter should be substantial enough to be a full scene or sequence. The chapter outline must serve TWO story arcs simultaneously:
