  '<h3>Sub-chapter ' + sc.number + ': ' + sc.title + '</h3>' +
  '<p><strong>Arc Beat (' + (chapterOutline.chapter_story_arc || '') + '):</strong> ' + (sc.arc_beat || '') + '</p>' +
  '<p><strong>Characters:</strong> ' + (sc.characters || []).join(', ') + '</p>' +
  '<p><strong>Setting:</strong> ' + (sc.setting || '') + '</p>' +
  '<p><strong>Emotional Tone:</strong> ' + (sc.emotional_tone || '') + '</p>' +
  '<p>' + (sc.brief || '') + '</p>' +
  '<p><em>Book Arc Connection:</em> ' + (sc.connects_to_book_arc || '') + '</p>'
).join('<hr>');

const displayTitle = chLabel + ' \u2014 ' + (chapterOutline.chapter_title || bookOutline.chapters[targetIdx].title || chLabel);

const emailBody = '<h1>Chapter Outline: ' + displayTitle + '</h1>' +
  '<p><strong>Book:</strong> ' + bookOutline.title + '</p>' +
  '<p><strong>Book Story Arc:</strong> ' + (s.bookArcName || 'Not specified') + '</p>' +
  '<p><strong>Chapter Story Arc:</strong> ' + (chapterOutline.chapter_story_arc || 'Same as book') + '</p>' +
  '<p><strong>Book Arc Beat:</strong> ' + (chapterOutline.book_arc_beat || '') + '</p>' +
  '<h2>Chapter Summary</h2><p>' + (chapterOutline.chapter_summary || '') + '</p>' +
  '<h2>Sub-Chapters (' + (chapterOutline.sub_chapters || []).length + ')</h2>' + subChList;

return [{ json: { 
