  result: 'Chapter outline created for "' + displayTitle + '" with ' + (chapterOutline.sub_chapters || []).length + ' sub-chapters using ' + (chapterOutline.chapter_story_arc || 'default') + ' story arc. Saved to project outline and emailed for review.'
